	@Test
	void canonicalizesRdfValuesUndefSetsMapsAndMetadata() throws Exception {
		TupleExpr original = parser.parse(node("BindingSetAssignment", fields(
				"declaredBindingNames", "[\"z\",\"plain\",\"typed\",\"directed\",\"triple\",\"bnode\",\"iri\"]",
				"bindingSets", "[{"
						+ field("z", iri("urn:z")) + ","
						+ field("plain", literal("plain")) + ","
						+ field("typed", "{\"type\":\"Literal\",\"label\":\"7\","
								+ "\"datatype\":\"http://www.w3.org/2001/XMLSchema#integer\"}")
						+ ","
						+ field("directed", "{\"type\":\"Literal\",\"label\":\"hello\","
								+ "\"language\":\"en\",\"direction\":\"RTL\"}")
						+ ","
						+ field("triple", "{\"type\":\"TripleTerm\","
								+ "\"subject\":" + iri("urn:s") + ","
								+ "\"predicate\":" + iri("urn:p") + ","
								+ "\"object\":" + literal("object") + "}")
						+ ","
						+ field("bnode", "{\"type\":\"BNode\",\"id\":\"b1\"}") + ","
						+ field("iri", iri("urn:i"))
						+ "}]",
				"variableScopeChange", "true",
				"resultSizeEstimate", "12.5",
				"costEstimate", "3.25",
				"optimizationTag", "17",
				"runtimeTelemetryEnabled", "true")));

		JsonNode first = writer.toJsonNode(original);
		JsonNode expression = first.path("expression");
		assertEquals(List.of("bnode", "directed", "iri", "plain", "triple", "typed", "z"),
				strings(expression.path("declaredBindingNames")));
		assertEquals(List.of("bnode", "directed", "iri", "plain", "triple", "typed", "z"),
				fieldNames(expression.path("bindingSets").get(0)));
		assertFalse(expression.path("bindingSets").get(0).path("z").isNull());
		assertEquals("RTL", expression.path("bindingSets").get(0).path("directed").path("direction").textValue());
		assertEquals(12.5, expression.path("resultSizeEstimate").doubleValue());
		assertEquals(3.25, expression.path("costEstimate").doubleValue());
		assertEquals(17, expression.path("optimizationTag").longValue());
		assertTrue(expression.path("runtimeTelemetryEnabled").booleanValue());
		assertCanonicalRoundTrip(original);
	}

	@Test
	void writesRepeatableCompactUtf8WithoutOwningTargets() throws Exception {
		TupleExpr expression = parser.parse(tupleExpressionCases().get("Service"));
		String expected = writer.toJson(expression);
		assertFalse(expected.contains("\n"));
		assertEquals(expected, writer.toJson(expression));

		TrackingWriter targetWriter = new TrackingWriter();
		writer.write(expression, targetWriter);
		assertEquals(expected, targetWriter.toString());
		assertFalse(targetWriter.closed);
		assertFalse(targetWriter.flushed);

		TrackingOutputStream targetStream = new TrackingOutputStream();
		writer.write(expression, targetStream);
		assertArrayEquals(expected.getBytes(StandardCharsets.UTF_8), targetStream.toByteArray());
		assertFalse(targetStream.closed);
		assertFalse(targetStream.flushed);
	}

	@Test
	void serializesSharedNodesAsIndependentSubtrees() throws Exception {
		SingletonSet shared = new SingletonSet();
		JsonNode json = writer.toJsonNode(new Join(shared, shared));
		assertEquals(json.at("/expression/leftArg"), json.at("/expression/rightArg"));

		Join parsed = (Join) parser.parse(json);
		assertNotSame(parsed.getLeftArg(), parsed.getRightArg());

		ExtensionElem sharedSource = new ExtensionElem(new Var("source"), "source");
		ProjectionElem first = new ProjectionElem("first");
		first.setSourceExpression(sharedSource);
		ProjectionElem second = new ProjectionElem("second");
		second.setSourceExpression(sharedSource);
		JsonNode projectionJson = writer.toJsonNode(
				new Projection(new SingletonSet(), new ProjectionElemList(first, second)));
		assertEquals(projectionJson.at("/expression/projectionElements/0/sourceExpression"),
				projectionJson.at("/expression/projectionElements/1/sourceExpression"));
	}

	@Test
	void rejectsUnsupportedCyclicDeepAndMalformedModels() {
		TupleExprJsonWriteException unsupported = assertThrows(TupleExprJsonWriteException.class,
				() -> writer.toJsonNode(new UnsupportedSingletonSet()));
		assertTrue(unsupported.getMessage().contains("$.expression.type"));
		assertTrue(unsupported.getMessage().contains("UnsupportedSingletonSet"));

		QueryRoot cycle = new QueryRoot(new SingletonSet());
		QueryRoot cycleChild = new QueryRoot(cycle);
		cycle.setArg(cycleChild);
		TupleExprJsonWriteException cycleError = assertThrows(TupleExprJsonWriteException.class,
				() -> writer.toJsonNode(cycle));
		assertTrue(cycleError.getMessage().contains("cycle"));

		TupleExpr deep = new SingletonSet();
		for (int i = 0; i < 512; i++) {
			deep = new QueryRoot(deep);
		}
		TupleExpr tooDeep = deep;
		TupleExprJsonWriteException depthError = assertThrows(TupleExprJsonWriteException.class,
				() -> writer.toJsonNode(tooDeep));
		assertTrue(depthError.getMessage().contains("maximum JSON/model depth"));

		TupleExprJsonWriteException malformed = assertThrows(TupleExprJsonWriteException.class,
				() -> writer.toJsonNode(new Projection()));
		assertTrue(malformed.getMessage().contains("$.expression.arg"));
	}

	@Test
	void rejectsOversizedStringsAndNonFiniteMetadata() {
		FunctionCall longFunction = new FunctionCall("x".repeat(MAX_JSON_STRING_LENGTH + 1));
		TupleExprJsonWriteException stringError = assertThrows(TupleExprJsonWriteException.class,
				() -> writer.toJsonNode(new Filter(new SingletonSet(), longFunction)));
		assertTrue(stringError.getMessage().contains("$.expression.condition.uri"));
		assertTrue(stringError.getMessage().contains("maximum length"));

		SingletonSet nonFinite = new SingletonSet();
		nonFinite.setCostEstimate(Double.NaN);
		TupleExprJsonWriteException numberError = assertThrows(TupleExprJsonWriteException.class,
				() -> writer.toJsonNode(nonFinite));
		assertTrue(numberError.getMessage().contains("$.expression.costEstimate"));
		assertTrue(numberError.getMessage().contains("SingletonSet"));
	}

	private void assertCanonicalRoundTrip(TupleExpr original) throws Exception {
		JsonNode first = writer.toJsonNode(original);
		TupleExpr imported = parser.parse(first);
		JsonNode second = writer.toJsonNode(imported);

		assertEquals(TupleExprJsonParser.FORMAT, first.path("format").textValue());
		assertEquals(TupleExprJsonParser.VERSION, first.path("version").intValue());
		assertEquals(first, second);
		assertEquals(original, imported);
		assertNotSame(original, imported);
		assertParentReferences(imported);
	}

	private static void assertParentReferences(TupleExpr root) {
		assertEquals(null, root.getParentNode());
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode parent) {
				parent.visitChildren(new AbstractQueryModelVisitor<RuntimeException>() {
					@Override
					protected void meetNode(QueryModelNode child) {
						assertSame(parent, child.getParentNode(),
								() -> child.getClass().getSimpleName() + " has wrong parent");
						child.visit(thisParentVisitor());
					}

					private AbstractQueryModelVisitor<RuntimeException> thisParentVisitor() {
						return TupleExprJsonWriterCoverageTest.parentVisitor(parent);
					}
				});
			}
		});
	}

	private static AbstractQueryModelVisitor<RuntimeException> parentVisitor(QueryModelNode expectedParent) {
		return new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				assertSame(expectedParent, node.getParentNode(),
						() -> node.getClass().getSimpleName() + " has wrong parent");
				node.visitChildren(new AbstractQueryModelVisitor<RuntimeException>() {
					@Override
					protected void meetNode(QueryModelNode child) {
						child.visit(parentVisitor(node));
					}
				});
			}
		};
	}

